namespace BlazorApp.Services;

public class Notification
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications;

    public NotificationService()
    {
        _notifications = new List<Notification>
        {
            new() { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) },
            new() { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
            new() { Id = _nextId++, Message = "New feature available: Dark Mode.", Timestamp = DateTime.UtcNow.AddMinutes(-2) }
        };
    }

    public Task<List<Notification>> GetNotificationsAsync()
    {
        return Task.FromResult(_notifications.ToList());
    }

    public Task<List<Notification>> GetNotificationsSinceAsync(int lastId)
    {
        // Simulate new notifications arriving occasionally
        if (Random.Shared.NextDouble() > 0.6)
        {
            _notifications.Add(new Notification
            {
                Id = _nextId++,
                Message = $"New event at {DateTime.UtcNow:HH:mm:ss}",
                Timestamp = DateTime.UtcNow
            });
        }

        var newer = _notifications.Where(n => n.Id > lastId).ToList();
        return Task.FromResult(newer);
    }
}

